//! macOS implementation of `AccessBackend`.
//!
//! Uses `<state root>/access-certs` (`~/.intendant/access-certs` by
//! default, `$INTENDANT_HOME/access-certs` when overridden) so native
//! `--tls` and `--mtls` can read the certs generated by
//! `intendant access setup`.

use std::path::PathBuf;
use std::process::Command;

use super::backend::AccessBackend;
use super::{AccessError, AccessResult};

pub struct MacOsBackend;

impl AccessBackend for MacOsBackend {
    fn cert_dir(&self) -> PathBuf {
        crate::platform::intendant_home().join("access-certs")
    }

    fn detect_primary_ip(&self) -> AccessResult<String> {
        // Get the default interface from `route -n get default`, then
        // its IP via `ipconfig getifaddr <iface>`.
        let route = Command::new("route")
            .args(["-n", "get", "default"])
            .output()
            .map_err(|e| AccessError(format!("route -n get default: {e}")))?;
        if !route.status.success() {
            return Err(AccessError("route -n get default failed".into()));
        }
        let stdout = String::from_utf8_lossy(&route.stdout);
        let iface = stdout
            .lines()
            .find_map(|l| l.trim().strip_prefix("interface:"))
            .map(|s| s.trim().to_string())
            .ok_or_else(|| AccessError("could not parse default interface".into()))?;

        let ip_out = Command::new("ipconfig")
            .args(["getifaddr", &iface])
            .output()
            .map_err(|e| AccessError(format!("ipconfig getifaddr {iface}: {e}")))?;
        let ip = String::from_utf8_lossy(&ip_out.stdout).trim().to_string();
        if ip.is_empty() {
            return Err(AccessError(format!("no IP detected for interface {iface}")));
        }
        println!(":: primary IP: {ip} (iface {iface})");
        Ok(ip)
    }
}
